vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;







vec2 uva = vUv;
vec2 uvb = vec2(1-vUv.x,vUv.y);

ret = texture(sampler_main, uva).x + texture(sampler_main, uvb).x;

vec3 blurs = GetBlur1(uva).x + GetBlur3(uva).x;
blurs += GetBlur1(uvb).x + GetBlur3(uvb).x;


vec2 uv3 = (vUv-.5)*(1-GetBlur1(vUv).zzz)+.5;
ret += clamp01(pow(texture(sampler_main, uv3).zzz,.5)*(1-ret.x*2)),
ret += clamp01(pow(GetBlur1(uv3).zzz,.5)*(1-ret.x*2)),


ret = mix(
blurs,
ret,
pow(ret,1));

ret = pow(ret,vec3(3,7,5));
vec4 noise9 = texture3D(sampler_noisevol_hq,
                      ((uv3.xyy*q28
                       )*uTexSize.xyy*texsize_noisevol_hq.zww
                      ).xyz*
                      vec3(11,1,0)*0.05 +
                      uTime*vec3(0,0,1)*q31
                     );
if(ret.x> q26/q13         && ret.x<= q23*q11        )ret.z -= (noise9).x*.5;
if(ret.y> q25/q11         && ret.y<= q22*q12        )ret.x -= (noise9).y*.5;
if(ret.z> q24/q12         && ret.z<= q21*q13        )ret.y -= (noise9).z*.5;
ret += pow(texture(sampler_main, vec2(vUv.x,1-vUv.y)).yyy+texture(sampler_main, 1-vUv).yyy,vec3(2,.7,.5));
ret *= 2;

ret /= vec3(3.2,3.2,2);
ret /= vec3(0.5,0.9,2.4);
ret /= vec3(2.9,1.0,-2.0);
//MilkDrop3 Shadows Mode:
ret += pow(texture(sampler_main,vec2(vUv.x,1-vUv.y)).yyy+texture(sampler_main,1-vUv).yyy,vec3(1,2,3));
//MilkDrop3 Rainbow Mode:
ret *= 1*normalize((texture(sampler_noise_hq,(vUv+q4/2)/6)));
//MilkDrop3 Blow Mode:
vec3 avg_col = GetBlur2(vUv);ret = abs(avg_col - ret)*2;
//MilkDrop3 Burn Mode:
ret = mix(ret,2,GetPixel(vUv).z*1.36);

